          return this.selectedFeature.getProperties() && !(this.selectedFeature.getProperties().type === 'Destroy' || this.selectedFeature.getProperties().type === 'Triangle' || this.selectedFeature.getProperties().type === 'FriendlyAttack' || this.selectedFeature.getProperties().type === 'Text');
